var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"좋은 아침임다, 할부지!","JPN":"おはようっす、爺ちゃん！","ENG":"Good morning, sir!","TWN":"早安，爺爺！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"으응? 누군가 했더니 모네구나? 그 낚싯대는 웬 거냐?","JPN":"おや？　モネじゃねえか。その釣竿はどうしたんじゃ？","ENG":"Huh? Oh, it's you, Mone. What's with the fishing rod?","TWN":"嗯？是莫妮啊！拿著釣魚竿幹什麼？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엄니가 피곤하대서 고기를 잡아다 드리러 왔슴다!","JPN":"母ちゃんが元気がないって言うから釣りに来たっす！","ENG":"I'm here to catch some fish for my mama because she's not feelin' so well!","TWN":"媽媽說她有點疲累，所以我來抓幾條魚給她補補！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"두고 보십셔! 이—따만한 월척을 잡아다 드릴 검다!","JPN":"ふふーん！　今日は大物釣って母ちゃんにごちそうするっすよ！","ENG":"Just you wait and see! I'll catch her a humongous fish!","TWN":"您看著吧！我一定會釣到這——麼大的魚！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"욘석도 참. 벌써부터 엄마 먼저 챙기고 다 컸구나.","JPN":"親孝行できてえらいのぅ。もうすっかり大きくなったもんじゃ。","ENG":"Good lass. You're taking good care of your mom. You're all grown up!","TWN":"妳這傢伙，都會孝順媽媽了，真是長大了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"헤헷. 동네 언니 오빠들은 다들 모네 나이 때부터 일하러 가지 않았슴까.","JPN":"へへっ。でも他の家の姉ちゃん兄ちゃんたちも、モネくらいの歳になったら働きに出てるっすよ。","ENG":"Heh heh. Everyone else in the village already started working at my age.","TWN":"嘿嘿，村子裡的哥哥姐姐們像我這麼大的時候就出去工作了。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"그래서 말인데 할부지, 혹시 바다 나가는 배 없슴까?","JPN":"ところで爺ちゃん。今日海に出る船はないっすか？","ENG":"So I was wondering, sir... Are there any boats headed out to sea today?","TWN":"對了，爺爺，有沒有出海的船啊？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"에그, 없지. 간밤에 저기 항만 쪽에서 총소리가 들려서 오늘은 다들 배 안 띄우려 할 텐데.","JPN":"ないんじゃないかのう。昨夜、港湾の方から銃声が聞こえたせいで、今日は船を出す人はおらんと思うのじゃ。","ENG":"Oh, I'm afraid not. We heard gunshots from the harbor last night. I doubt anyone wants to sail today.","TWN":"哎呀，沒有。昨晚從那邊的港灣傳來了槍聲，所以今天大家都不敢出海。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"엑, 진짜임까?","JPN":"ええーほんとっすか？","ENG":"Oh, no! Really?","TWN":"啊，真的？"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그래. 차라리 해변 끄트머리로 가 보려무나.","JPN":"そうじゃ。海辺の方へ行ってみたらどうじゃ。","ENG":"That's right. Why don't you check out the edge of the shoreline instead?","TWN":"是啊，妳要不要去海邊的盡頭看看。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"타지에서 온 낚시꾼들이 그리로 자주 가니까.","JPN":"その辺なら他所から来た釣り人がよくいるからの。","ENG":"A lot of the fishermen visiting from other regions flock there.","TWN":"外地來的垂釣者常去那裡呢。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"오오......! 고맙슴다, 할부지!","JPN":"おお……！　爺ちゃん、ありがとうっす！","ENG":"Oh! Thank you, sir!","TWN":"噢噢……！謝謝你，爺爺！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"......한참 기다려도 송사리 한 마리 안 보이지 말임다.","JPN":"……ずっと待ってるけど、メダカ1匹すら釣れないっす。","ENG":"... I've been fishin' forever and I haven't caught a thing.","TWN":"……釣了半天，連個小蝦米都沒有。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"이대로 빈손으로 돌아가면 아부지가 또 놀릴지도 모름다.","JPN":"このままボウズで帰ったら父ちゃんにまた笑われるっす。","ENG":"Papa will surely make fun of me again if I go back empty-handed.","TWN":"如果空手而回，爸爸一定又會笑我的。"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"<color=#ffd34c>하하! 우리 딸, 그 성격에 낚시 배우려면 백 년은 더 걸릴 걸?</color>","JPN":"<color=#ffd34c>ガハハハッ！　その調子じゃ、釣れるまであと100年はかかるぞ！</color>","ENG":"<color=#ffd34c>Hah hah! My impatient girl, it'll take another hundred years for you to learn how to fish properly!</color>","TWN":"<color=#ffd34c>哈哈！我的女兒，就妳那個性格也想學釣魚，至少還得一百年。</color>"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"<color=#ffd34c>눈썹 씰룩씰룩.</color>","JPN":"<color=#ffd34c>(ドヤ顔)</color>","ENG":"<color=#ffd34c>And he'll wiggle his eyebrows.</color>","TWN":"<color=#ffd34c>眉毛抖啊抖。</color>"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TONFA_MAID_NORMAL_NULL","text":{"KOREA":"으으! 당할 순 없슴다!","JPN":"む……！　このまま帰るわけにはいかないっす！","ENG":"Ugh! I'm not gonna let it come to that!","TWN":"啊啊！我可受不了！"},"stage":{"bg":"SUMMER_BEACH","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NORMAL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};